transform_js:
const datesObj = {}; const catObj = {};
rawData.rows.forEach(r => { datesObj[r.date] = true; catObj[r.category] = true; });
const dates = Object.keys(datesObj);
const categories = Object.keys(catObj);
const seriesData = categories.map(cat => {
   return {
       name: cat,
       type: 'line',
       stack: 'Total',
       areaStyle: {},
       emphasis: {
          focus: 'series'
       },
       data: dates.map(d => {
          const found = rawData.rows.find(r => r.date === d && r.category === cat);
          return found ? found.value : 0;
       })
   };
});
transformedData = { dates, seriesData, categories };

echarts_js:
option = {
  title: {
    text: 'Traffic Sources (Stacked Area)',
    left: 'center'
  },
  tooltip: {
    trigger: 'axis',
    axisPointer: {
      type: 'cross',
      label: { backgroundColor: '#6a7985' }
    }
  },
  legend: {
    data: transformedData.categories,
    bottom: 10
  },
  grid: {
    left: '3%',
    right: '4%',
    bottom: '15%',
    containLabel: true
  },
  xAxis: [
    {
      type: 'category',
      boundaryGap: false,
      data: transformedData.dates
    }
  ],
  yAxis: [
    {
      type: 'value'
    }
  ],
  series: transformedData.seriesData
};
